# -*- coding: utf-8 -*-
import os

def item(prefix, idx, chapter, name, content):
    return f"        {{ id: '{prefix}-{idx}', chapter: '{chapter}', name: '{name}', content: '{content}' }}"

def generate_subject(prefix, items_list):
    lines = []
    for i, (ch, name, content) in enumerate(items_list, 1):
        idx = f"{prefix}-g3-{i}"
        lines.append(item(prefix, f"g3-{i}", ch, name, content))
    return ",\n".join(lines)

